posts=re.findall(r'href=[\"\'](post\.php\?id=[^\"\']+)', html_index)
urls += [f'{base}/'+p for p in posts]
for u in urls:
    t=sess.get(u).text
    cands=re.findall(r'([A-Za-z0-9+/]{16,}={0,2})', t)
    decs=[]
    for s in set(cands):
        try:
            d=base64.b64decode(s + '==='[:(4-len(s)%4)%4])
            if b'FLAG' in d or b'flag' in d or b'CTF' in d:
                decs.append((s,d.decode(errors='ignore')))
        except binascii.Error:
            pass
    if decs:
        print('URL:', u)
        for s,d in decs:
            print('b64:', s, '->', d)

